#include <stdio.h>
#include <stdint.h>
#define MOD 163577857

int64_t powmod(int64_t base, int64_t exponent, int64_t mod) {
    int64_t result = 1;
    while (exponent > 0) {
        if (exponent & 1) {
            result = (result * base) % mod;
        }
        exponent >>= 1;
        base = (base * base) % mod;
    }
    return result;
}

int64_t inverse(int64_t a, int64_t m) {
    int64_t m0 = m;
    int64_t y = 0, x = 1;
    if (m == 1)
        return 0;
    while (a > 1) {
        int64_t q = a / m;
        int64_t t = m;
        m = a % m;
        a = t;
        t = y;
        y = x - q * y;
        x = t;
    }
    if (x < 0)
        x += m0;
    return x;
}

int64_t combination(int64_t n, int64_t k, int64_t mod) {
    int64_t numerator = 1;
    for (int64_t i = 1; i <= k; i++) {
        numerator = (numerator * (n - i + 1)) % mod;
    }
    int64_t denominator = 1;
    for (int64_t i = 1; i <= k; i++) {
        denominator = (denominator * i) % mod;
    }
    return (numerator * inverse(denominator, mod)) % mod;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int64_t n, k;
        scanf("%lld %lld", &n, &k);
        int64_t result = 0;
        for (int64_t i = 0; i <= k - 1; i++) {
            result = (result + combination(n + i, i + 1, MOD)) % MOD;
        }
        printf("%lld\n", result);
    }
    return 0;
}

