import java.util.Scanner;
public class Main {
    static final long MOD = 163577857;
    public static long powmod(long base, long exponent, long mod) {
        long result = 1;
        while (exponent > 0) {
            if (exponent % 2 == 1) {
                result = (result * base) % mod;
            }
            exponent >>= 1;
            base = (base * base) % mod;
        }
        return result;
    }
    public static long inverse(long a, long m) {
        long m0 = m;
        long y = 0, x = 1;
        if (m == 1)
            return 0;
        while (a > 1) {
            long q = a / m;
            long t = m;
            m = a % m;
            a = t;
            t = y;
            y = x - q * y;
            x = t;
        }
        if (x < 0)
            x += m0;
        return x;
    }
    public static long combination(long n, long k, long mod) {
        long numerator = 1;
        for (long i = 1; i <= k; i++) {
            numerator = (numerator * (n - i + 1)) % mod;
        }
        long denominator = 1;
        for (long i = 1; i <= k; i++) {
            denominator = (denominator * i) % mod;
        }
        return (numerator * inverse(denominator, mod)) % mod;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            long n = scanner.nextLong();
            long k = scanner.nextLong();
            long result = 0;
            for (long i = 0; i <= k - 1; i++) {
                result = (result + combination(n + i, i + 1, MOD)) % MOD;
            }
            System.out.println(result);
        }
    }
}

